public class TestJSON { public static void main(String[] args) { String json = "{\"name\":\"Test\",\"nameVi\":\"TestVi\",\"description\":\"\",\"displayOrder\":1}"; System.out.println("description=" + extractString(json, "description")); System.out.println("displayOrder=" + extractString(json, "displayOrder")); } private static String extractString(String json, String key) { String search = "\"" + key + "\":\""; int idx = json.indexOf(search); if (idx == -1) { search = "\"" + key + "\":"; idx = json.indexOf(search); if (idx == -1) return ""; int start = idx + search.length(); int end = json.indexOf(",", start); if (end == -1) end = json.indexOf("}", start); return json.substring(start, end).trim(); } int start = idx + search.length(); int end = json.indexOf("\"", start); if (end == -1) return ""; return json.substring(start, end); } }
